question.answer:
char *str_rev(char src[]){
	char *s = src, *e = src;
	while(*++e != '\0'); // iterate e until null
	while(--e > s){ 
		// spooky scary swap op
		*s ^= *e;
		*e ^= *s;
		*s++ ^= *e;
	}

	return src;
}

testcode.text:
char str[] = "Reverse";
printf("%s\n", str_rev(str));
printf("%s\n", str);

char str[] = "Another test";
printf("%s\n", str_rev(str));
printf("%s\n", str);

regex_t regex;
int reti;
reti = regcomp(&regex, "[[:space:]]*char[[:space:]]+[[:alpha:]]+\\[[[:alnum:]]*\\][^\n]*;", REG_EXTENDED | REG_NOSUB);
reti = regexec(&regex, input, 0, NULL, 0);
if (!reti) {
    printf("Array detected! If you see this and didn't use an array, show your code to Andrew.\n");
}
else if (reti == REG_NOMATCH) {
    printf("No array detected!\n");
}
regfree(&regex);

regex_t regex;
int reti;
reti = regcomp(&regex, "(<string[.]h>|strlen)", REG_EXTENDED | REG_NOSUB);
reti = regexec(&regex, input, 0, NULL, 0);
if (!reti) {
    printf("Nice Try, but you can't use string.h!\n");
}
else if (reti == REG_NOMATCH) {
    printf("Okay");
}
regfree(&regex);
